import org.owasp.esapi.ESAPI;
import org.owasp.esapi.Encoder;

public class SecureCode {

    public static void main(String[] args) {
        // Simulating user input from a form field
        String userInput = "<script>alert('XSS Vulnerability')</script>";

        // Properly encode user input to prevent XSS
        Encoder encoder = ESAPI.encoder();
        String encodedInput = encoder.encodeForHTML(userInput);

        // Output the sanitized input
        String output = "Welcome, " + encodedInput;

        System.out.println(output);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
